import{_ as o,o as e,c as s,ay as r}from"./chunks/framework.-lzFfN-z.js";const l="/CoreFront-EndConcepts/xssAttack.png",n="/CoreFront-EndConcepts/xssDefense.png",a="/CoreFront-EndConcepts/csrfAttack.png",i="/CoreFront-EndConcepts/csrfDefense.png",p=JSON.parse('{"title":"XSS 和 CSRF","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/csrfAndXss.md","filePath":"networkAndBrowsers/csrfAndXss.md","lastUpdated":1779843930000}'),d={name:"networkAndBrowsers/csrfAndXss.md"};function g(c,t,S,h,f,u){return e(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="xss-和-csrf" tabindex="-1">XSS 和 CSRF <a class="header-anchor" href="#xss-和-csrf" aria-label="Permalink to &quot;XSS 和 CSRF&quot;">​</a></h1><p>在 Web 安全领域，<strong>XSS（跨站脚本攻击）</strong> 和 <strong>CSRF（跨站请求伪造）</strong> 是最古老、最常见也是面试中必考的两种攻击方式, 虽然它们名字很像，但它们的<strong>攻击目标、原理和防御手段截然不同</strong>。</p><h2 id="_1-xss-cross-site-scripting-跨站脚本攻击" tabindex="-1">1. XSS (Cross-Site Scripting) 跨站脚本攻击 <a class="header-anchor" href="#_1-xss-cross-site-scripting-跨站脚本攻击" aria-label="Permalink to &quot;1. XSS (Cross-Site Scripting) 跨站脚本攻击&quot;">​</a></h2><p><strong>核心本质</strong>：攻击者想方设法将<strong>恶意的 JavaScript 代码</strong>注入到你的网站页面中，并让受害者的浏览器执行。</p><p><strong>攻击目标</strong>：客户端（用户的浏览器）。</p><p><strong>一句话理解</strong>：<strong>“你的网站执行了别人的代码。”</strong></p><h3 id="_1-1-xss-的三种主要类型" tabindex="-1">1.1 XSS 的三种主要类型 <a class="header-anchor" href="#_1-1-xss-的三种主要类型" aria-label="Permalink to &quot;1.1 XSS 的三种主要类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">原理</th><th style="text-align:left;">攻击路径示例</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>存储型 (Stored)</strong></td><td style="text-align:left;">恶意脚本被<strong>永久存储在目标服务器</strong>（数据库、文件系统）中。危害最大。</td><td style="text-align:left;">1. 攻击者在网站的评论区输入 <code>&lt;script&gt;窃取Cookie代码&lt;/script&gt;</code> 并提交。<br>2. 服务器将评论存入数据库。<br>3. <strong>所有</strong>访问该评论页面的用户，浏览器都会执行这段恶意代码。</td></tr><tr><td style="text-align:left;"><strong>反射型 (Reflected)</strong></td><td style="text-align:left;">恶意脚本作为<strong>请求参数（如 URL）<strong>发送给服务器，服务器</strong>未做处理</strong>直接将脚本“反射”回 HTML 页面。</td><td style="text-align:left;">1. 攻击者构造恶意链接 <code>http://test.com/search?q=&lt;script&gt;...&lt;/script&gt;</code> 并发送给受害者。<br>2. 受害者点击链接。<br>3. 服务器返回包含恶意脚本的搜索结果页面。<br>4. 脚本在受害者浏览器执行。</td></tr><tr><td style="text-align:left;"><strong>DOM 型 (DOM-based)</strong></td><td style="text-align:left;">纯粹的<strong>前端漏洞</strong>。前端 JS 代码在处理 URL 参数、Hash 或其他输入时，未经转义直接操作了 DOM。</td><td style="text-align:left;">1. 网址带有恶意参数 <code>http://test.com/#&lt;script&gt;...&lt;/script&gt;</code>。<br>2. 页面上的 JS 代码读取了 Hash 值并直接用 <code>innerHTML</code> 插入到页面。<br>3. 脚本执行。整个过程<strong>恶意代码不经过服务器</strong>。</td></tr></tbody></table><p><img src="'+l+'" alt="Logo" data-zoomable="true"></p><h3 id="_1-2-xss-的危害" tabindex="-1">1.2 XSS 的危害 <a class="header-anchor" href="#_1-2-xss-的危害" aria-label="Permalink to &quot;1.2 XSS 的危害&quot;">​</a></h3><ul><li><strong>窃取 Cookie 和 Session ID</strong>：利用 <code>document.cookie</code> 获取后发送到攻击者服务器，直接盗用用户账号。</li><li><strong>页面篡改/钓鱼</strong>：修改页面内容，弹出一个假的登录框骗取密码。</li><li><strong>键盘记录</strong>：监听用户的按键操作。</li><li><strong>发起 CSRF 攻击</strong>：利用窃取到的凭证，在后台悄悄执行敏感操作。</li></ul><h3 id="_1-3-xss-的防御手段-防线" tabindex="-1">1.3 XSS 的防御手段 (防线) <a class="header-anchor" href="#_1-3-xss-的防御手段-防线" aria-label="Permalink to &quot;1.3 XSS 的防御手段 (防线)&quot;">​</a></h3><ul><li><strong>防线一：输入过滤/转义 (Sanitization / Escaping)</strong>。 <ul><li><strong>永远不要相信用户的输入。</strong> 任何从客户端提交到服务器，或者从 URL 读取并展示到页面的数据，都必须进行转义（例如将 <code>&lt;</code> 转义为 <code>&amp;lt;</code>，<code>&gt;</code> 转义为 <code>&amp;gt;</code>）。可以使用如 <code>sanitize-html</code> 这样的库。</li></ul></li><li><strong>防线二：设置 <code>HttpOnly</code> Cookie</strong>。 <ul><li>在服务器端设置 Cookie 时加上 <code>HttpOnly</code> 标志。这会让浏览器<strong>禁止</strong> JavaScript 通过 <code>document.cookie</code> 读取该 Cookie。即使 XSS 攻击成功，黑客也偷不到关键的身份令牌。</li></ul></li><li><strong>防线三：内容安全策略 (CSP, Content Security Policy)</strong>。 <ul><li>通过 HTTP 响应头配置，建立一个白名单，告诉浏览器“只允许加载和执行来自特定域名的脚本”。即使黑客注入了脚本，浏览器也会拒绝执行。</li></ul></li></ul><p><img src="'+n+'" alt="Logo" data-zoomable="true"></p><h2 id="_2-csrf-cross-site-request-forgery-跨站请求伪造" tabindex="-1">2. CSRF (Cross-Site Request Forgery) 跨站请求伪造 <a class="header-anchor" href="#_2-csrf-cross-site-request-forgery-跨站请求伪造" aria-label="Permalink to &quot;2. CSRF (Cross-Site Request Forgery) 跨站请求伪造&quot;">​</a></h2><p><strong>核心本质</strong>：攻击者利用受害者<strong>在目标网站已登录的身份（浏览器自动携带 Cookie 的机制）</strong>，诱导受害者在不知情的情况下，对目标网站发送恶意请求。</p><p><strong>攻击目标</strong>：服务端（利用服务端的信任机制）。</p><p><strong>一句话理解</strong>：<strong>“你代替黑客，向服务器发出了指令。”</strong></p><h3 id="_2-1-csrf-攻击的工作流程" tabindex="-1">2.1 CSRF 攻击的工作流程 <a class="header-anchor" href="#_2-1-csrf-攻击的工作流程" aria-label="Permalink to &quot;2.1 CSRF 攻击的工作流程&quot;">​</a></h3><ol><li>用户登录了银行网站 <code>bank.com</code>，浏览器保存了包含身份信息的 Cookie。</li><li>用户在<strong>没有登出</strong>银行网站的情况下，被诱导访问了黑客的恶意网站 <code>hacker.com</code>。</li><li>黑客的网站里隐藏了一段代码，例如一个不可见的图片标签： <code>&lt;img src=&quot;http://bank.com/transfer?to=hacker&amp;money=10000&quot; /&gt;</code></li><li>用户的浏览器会自动解析这个 <code>&lt;img&gt;</code> 标签，并向 <code>bank.com</code> 发起一个 GET 请求。</li><li><strong>最关键的一步</strong>：因为用户之前登录过 <code>bank.com</code>，浏览器在发起这个请求时，会<strong>自动、默认地带上 <code>bank.com</code> 的 Cookie</strong>。</li><li>银行服务器收到请求，验证 Cookie 发现是合法用户，于是执行了转账操作。</li></ol><p><img src="'+a+'" alt="Logo" data-zoomable="true"></p><h3 id="_2-2-csrf-攻击成功的三个条件" tabindex="-1">2.2 CSRF 攻击成功的三个条件 <a class="header-anchor" href="#_2-2-csrf-攻击成功的三个条件" aria-label="Permalink to &quot;2.2 CSRF 攻击成功的三个条件&quot;">​</a></h3><ul><li>目标网站存在可以通过 API 执行的敏感操作（如转账、修改密码）。</li><li>受害者刚刚登录过目标网站，且<strong>浏览器中的 Cookie 未过期</strong>。</li><li>受害者在未登出的状态下，访问了攻击者精心构造的恶意页面。</li></ul><h3 id="_2-3-csrf-的防御手段" tabindex="-1">2.3 CSRF 的防御手段 <a class="header-anchor" href="#_2-3-csrf-的防御手段" aria-label="Permalink to &quot;2.3 CSRF 的防御手段&quot;">​</a></h3><ul><li><strong>防线一：同源检测 (Referer Check / Origin Check)</strong>。 <ul><li>服务器在收到请求时，检查 HTTP 头部的 <code>Referer</code> 或 <code>Origin</code> 字段。如果发现请求是从 <code>hacker.com</code> 发过来的，而不是从 <code>bank.com</code> 自家的页面发过来的，就直接拒绝请求。</li></ul></li><li><strong>防线二：CSRF Token 验证 (最主流防线)</strong>。 <ul><li><strong>原理</strong>：既然浏览器会自动携带 Cookie，那我们就要求请求中必须携带一个<strong>浏览器不会自动发送</strong>的东西。</li><li><strong>做法</strong>：用户打开页面时，服务器生成一个随机的 CSRF Token（存放在 HTML 隐藏字段或由 JS 提取）。当用户发起敏感请求（如表单提交、Ajax）时，必须将这个 Token 作为参数或 Request Header 发送给服务器。因为黑客的网站无法跨域读取到这个 Token，伪造的请求就会被服务器拒绝。</li></ul></li><li><strong>防线三：Cookie 的 <code>SameSite</code> 属性</strong>。 <ul><li>现代浏览器的神器。为 Cookie 设置 <code>SameSite=Strict</code> 或 <code>Lax</code>。这会告诉浏览器：“只有在当前网页和 Cookie 所属域名<strong>完全一致</strong>（同站）时，才允许携带此 Cookie；如果是从其他网站（跨站）发起的请求，<strong>绝对不允许</strong>携带”。这从根本上切断了 CSRF 的命脉。</li></ul></li></ul><p><img src="'+i+'" alt="Logo" data-zoomable="true"></p><h2 id="_3-xss-vs-csrf-深度对比及常见问题-faq" tabindex="-1">3. XSS vs CSRF 深度对比及常见问题 (FAQ) <a class="header-anchor" href="#_3-xss-vs-csrf-深度对比及常见问题-faq" aria-label="Permalink to &quot;3. XSS vs CSRF 深度对比及常见问题 (FAQ)&quot;">​</a></h2><h3 id="_3-1-xss-vs-csrf-有什么差异" tabindex="-1">3.1 XSS vs CSRF 有什么差异？ <a class="header-anchor" href="#_3-1-xss-vs-csrf-有什么差异" aria-label="Permalink to &quot;3.1 XSS vs CSRF 有什么差异？&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">对比维度</th><th style="text-align:left;">XSS (跨站脚本)</th><th style="text-align:left;">CSRF (跨站请求伪造)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>攻击方式</strong></td><td style="text-align:left;">向页面<strong>注入并执行</strong>恶意 JS 脚本。</td><td style="text-align:left;"><strong>借用用户身份</strong>，伪造请求发送给服务器。</td></tr><tr><td style="text-align:left;"><strong>攻击目标</strong></td><td style="text-align:left;">用户的浏览器。</td><td style="text-align:left;">服务器。</td></tr><tr><td style="text-align:left;"><strong>是否需要登录</strong></td><td style="text-align:left;">不需要（任何人访问受污染页面都会中招）。</td><td style="text-align:left;"><strong>必须</strong>（依赖受害者已登录的有效 Cookie）。</td></tr><tr><td style="text-align:left;"><strong>对用户凭证的操作</strong></td><td style="text-align:left;">试图<strong>窃取</strong>用户的 Cookie/Token 送给黑客。</td><td style="text-align:left;">并不窃取，只是<strong>利用</strong>浏览器自动带 Cookie 的机制。黑客全程<strong>看</strong>不到 Cookie 的内容。</td></tr><tr><td style="text-align:left;"><strong>防御核心思路</strong></td><td style="text-align:left;">永远不信任用户输入（过滤、转义、限制脚本）。</td><td style="text-align:left;">确认请求的来源和意图（Token 校验、SameSite）。</td></tr></tbody></table><h3 id="_3-2-为什么用了-jwt-token-就不需要防范-csrf-了" tabindex="-1">3.2 为什么用了 JWT (Token) 就不需要防范 CSRF 了？ <a class="header-anchor" href="#_3-2-为什么用了-jwt-token-就不需要防范-csrf-了" aria-label="Permalink to &quot;3.2 为什么用了 JWT (Token) 就不需要防范 CSRF 了？&quot;">​</a></h3><ul><li>这是一个常见误区，答案取决于你的 Token <strong>存在哪里</strong>。 <ul><li>如果你的 JWT 存在 <strong>Cookie</strong> 中，你<strong>依然</strong>会受到 CSRF 攻击，因为浏览器还是会自动携带它。</li><li>只有当你把 JWT 存放在 <code>localStorage/sessionStorage</code> 中，并在发请求时<strong>使用 JS 手动将其添加到 HTTP Header（如 <code>Authorization: Bearer &lt;token&gt;</code>）中</strong>时，才天然免疫 CSRF。因为黑客的伪造请求（如 <code>&lt;img&gt;</code> 或跨域 <code>&lt;form&gt;</code> 提交）无法触发你的前端 JS 代码去读取 localStorage 并塞入 Header。</li></ul></li></ul><h3 id="_3-3-csrf-token-可以防止-xss-攻击吗" tabindex="-1">3.3 CSRF Token 可以防止 XSS 攻击吗？ <a class="header-anchor" href="#_3-3-csrf-token-可以防止-xss-攻击吗" aria-label="Permalink to &quot;3.3 CSRF Token 可以防止 XSS 攻击吗？&quot;">​</a></h3><ul><li>绝对不能，甚至会被 XSS 秒杀。 <ul><li>如果你的网站存在 XSS 漏洞，黑客注入的恶意脚本可以直接读取你页面上的 CSRF Token（无论是写在 DOM 里还是存在全局变量里），然后带着这个合法的 Token 发起 CSRF 请求。</li><li><strong>结论</strong>：XSS 漏洞的危险级别远高于 CSRF，因为<strong>一旦发生 XSS，所有的 CSRF 防御措施（除 SameSite 且不允许 JS 读取的 Cookie 外）都将形同虚设</strong>。</li></ul></li></ul><h3 id="_3-4-设置了-httponly-就能完全防止-xss-吗" tabindex="-1">3.4 设置了 <code>HttpOnly</code> 就能完全防止 XSS 吗？ <a class="header-anchor" href="#_3-4-设置了-httponly-就能完全防止-xss-吗" aria-label="Permalink to &quot;3.4 设置了 `HttpOnly` 就能完全防止 XSS 吗？&quot;">​</a></h3><ul><li>不能完全防止，只能减轻危害。 <ul><li><code>HttpOnly</code> 只能防止通过 JS 读取 Cookie（防盗号）。但 XSS 的危害不仅限于偷 Cookie。</li><li>如果发生了 XSS，黑客依然可以通过执行 JS 脚本来<strong>操纵 DOM（例如修改收款账号）、发起 Ajax 请求执行任意操作（此时浏览器仍会自动带上 HttpOnly 的 Cookie 发给服务器）</strong>。所以，防范 XSS 的根本还是输入输出的过滤和转义。</li></ul></li></ul>',35)])])}const C=o(d,[["render",g]]);export{p as __pageData,C as default};
